VALUES
  ('optician-moex-01849', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關乾眼症與隱形眼鏡的敘述，下列何者錯誤？', '["有角膜破皮的病人，可以配戴治療型隱形眼鏡來幫助角膜癒合", "配戴軟式隱形眼鏡比較會有乾眼的症狀", "建議可配戴高含水量水膠隱形眼鏡", "建議可配戴矽水膠隱形眼鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01850', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡之矢高（sagittal height），下列何者正確？', '["鏡片基弧不變，減少鏡片總直徑，則矢高減少", "鏡片總直徑不變，減少鏡片基弧，則矢高減少", "矢高增加，鏡片配適（lens fit）變鬆", "矢高的變化與鏡片配適鬆緊度無關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01851', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜上方表皮弧形損傷（SEALs, superior epithelial arcuate lesions）的敍述，下列何者錯誤？', '["角膜上方表皮弧形損傷屬於一種機械性損傷造成的角膜上皮剝落（split）", "愈剛硬材質（stiffness）的鏡片愈容易出現此種併發症", "患者通常不會出現嚴重症狀", "配戴矽水膠鏡片不會出現此種併發症"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01852', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位剛開始使用軟式隱形眼鏡二個月的15歲女性，主訴最近雙眼有異物感，眼睛紅，流淚。在檢查中你 發現雙眼靠近上輪部的地方有發紅，水腫和局部角膜上皮點狀染色的現象，最符合的診斷為何？', '["乾眼症", "乳突狀結膜炎（papillary conjunctivitis）", "皰疹性角膜炎（herpetic keratitis）", "上輪部角結膜炎（superior limbic keratoconjunctivitis）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01853', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列敘述何者錯誤？', '["角膜主要是從大氣中取得氧氣供應", "硫柳汞（thimerosal）是一種導致敏感性反應的舊式隱形眼鏡藥水防腐劑", "一種因為隱形眼鏡鏡片配適或眼瞼太緊而形成的角膜螢光染色簡稱為SEALs", "出現在瞼結膜上，被微血管包圍的突起，一般因炎症引起，稱為乳突（papillae）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01854', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜3和9點鐘方向染色的敘述，下列何者錯誤？', '["以螢光素協助確定角膜上皮層細胞受損的症狀稱為染色（staining）", "角膜出現3和9點鐘方向染色是配戴硬式高透氧隱形眼鏡常見的一種併發症", "鏡片後表面採用非球面設計有助於減少角膜出現3和9點鐘方向染色的機率", "角膜弧度儀（keratometry）是用以檢查角膜輪廓的儀器，對這類患者之檢查相當有幫助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01855', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關棘狀阿米巴角膜炎之敘述，下列何者錯誤？', '["常和隱形眼鏡配戴有關", "儘早角膜移植為最佳的治療方式", "初期常被誤診為皰疹性角膜炎", "以抗生素治療效果不佳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01856', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關棘狀阿米巴原蟲的敘述，下列何者錯誤？', '["不論是雙氧水消毒系統、多用途清洗藥水或是透氣硬性隱形眼鏡的消毒藥水，都無法徹底殺滅所有棘 狀阿米巴原蟲", "鏡片戴用一段時間後鏡片自淚液中吸取蛋白質而淤積，鏡片一旦淤積蛋白質，消毒藥水更難殺滅棘狀 阿米巴原蟲", "24小時長戴隱形眼鏡令角膜受損或游泳時戴隱形眼鏡可能引發眼部棘狀阿米巴原蟲感染", "眼部受一般細菌入侵者都會即時眼紅及疼痛，棘狀阿米巴原蟲則症狀比較不疼痛，但是感染約 2 至 3 小時內，視力迅速轉差，需緊急進行角膜移植手術"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01857', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列敘述何者正確？', '["Dk是量度鏡片物料氧氣透氧率（permeability）的指標", "在隱形眼鏡上積聚的生化沉積物稱為條紋（striae）", "角膜中最厚的一層組織為德士密氏膜（Descemet''s membrane）", "角膜因氧氣不足所產生的情況稱為角膜充血（hyperemia）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01858', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡引起的乳突狀結膜炎症狀，下列敘述何者錯誤？', '["通常在球結膜發現", "結膜上出現局部腫脹或乳突", "有時有輕度眼瞼下垂", "角膜可能出現點狀染色"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "82f5f57228b7", "answer_pdf_sha1": "bf4e216f26e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
